import React, { useState, useEffect, useCallback, useMemo } from 'react';
// import { useRouteMatch, } from 'react-router-dom';
import {
   getArticlesNews,
   getTrendingNews,
   getCategoryNews,
} from '../../api/api';
import './HomePage.scss';

export const HomePage = () => {
  const [trendingNews, setTrendingNews] = useState([]);
  const [articles, setArticles] = useState({});
  const [author, setAuthor] = useState({});
  const [datePublished, setDatePublished] = useState({});
  const [categoryNews, setCategoryNews] = useState([]);
  const [categoryArticles, setCategoryArticles] = useState({});
  const [categoryAuthor, setCategoryAuthor] = useState({});
  const [category, setCategory] = useState('world');

  useEffect(() => {
    getTrendingNews().then(res => setTrendingNews(
      res.value.map((news, index) => {
        getArticlesNews(news.query.text)
          .then((art) => {
            setArticles(articles => ({
              ...articles,
              [news.query.text]: art[0].summary,
            }));
            setAuthor(author => ({
              ...author,
              [news.query.text]: art[0].author || 'no author',
            }));
            setDatePublished(datePublished => ({
              ...datePublished,
              [news.query.text]: art[0].published_date.slice(0, 10),
            }));
          });

        return (
          {
            id: index + 1,
            type: 'trending',
            name: news.query.text,
            image: news.image.url,
          });
      }),
    ));
  }, []);

  useMemo(() => {
    if (articles) {
      setTrendingNews(trendingNews
        .map(news => ({
          ...news,
          summary: articles[news.name],
          author: author[news.name],
          date: datePublished[news.name],
        })));
    }
  }, [articles, author, datePublished]);

  console.log(trendingNews, articles, author);

